mapper.select:
select jdh.*, s.supplier OrganName, u.username userName, a."name" AccountName from (select dh.id from jsh_depot_head dh left join jsh_depot_item di on dh.id = di.header_id and COALESCE(di.delete_flag,'0') !='1' left join jsh_material m on di.material_id = m.id and COALESCE(m.delete_flag,'0') !='1' left join jsh_material_extend me on di.material_extend_id = me.id and COALESCE(me.delete_flag,'0') !='1' where 1=1
and dh."type"=#{type}
and dh.sub_type=#{subType}
and dh.status in (
#{status}
)
and dh.purchase_status in (
#{purchaseStatus}
)
and dh.number like #{bindNumber}
and dh.link_apply like #{bindLinkApply}
and dh.link_number like #{bindLinkNumber}
and dh.oper_time >= #{beginTime}::timestamp
and dh.oper_time <= #{endTime}::timestamp
and (me.bar_code like #{bindKey} or m."name" like #{bindKey} or m.mnemonic like #{bindKey} or m.standard like #{bindKey} or m.model like #{bindKey} or m.color like #{bindKey} or m.mfrs like #{bindKey} or m.brand like #{bindKey} or m.other_field1 like #{bindKey} or m.other_field2 like #{bindKey} or m.other_field3 like #{bindKey})
and dh.organ_id=#{organId}::bigint
and dh.organ_id in (
#{organId}::bigint
)
and dh.creator=#{creator}::bigint
and di.depot_id=#{depotId}::bigint
and di.depot_id in (
#{depotId}::bigint
)
and dh.creator in (
#{creator}::bigint
)
and (dh.account_id=#{accountId} or dh.account_id_list like #{bindAccountId})
and (COALESCE(dh.discount_last_money,0)+COALESCE(dh.other_money,0)-COALESCE(dh.deposit,0)-abs(COALESCE(dh.change_amount,0))>0)
and (COALESCE(dh.discount_last_money,0)+COALESCE(dh.other_money,0)-COALESCE(dh.deposit,0)-abs(COALESCE(dh.change_amount,0))=0)
and COALESCE(dh.last_debt,0)>0
and COALESCE(dh.last_debt,0)=0
and dh.sales_man ~ ('(^|,)' || #{salesMan}::text || '(,|$)')
and (dh.remark like #{bindRemark} or di.remark like #{bindRemark})
and COALESCE(dh.delete_flag,'0') !='1' group by dh.id order by dh.id desc) tb left join jsh_depot_head jdh on jdh.id=tb.id and COALESCE(jdh.delete_flag,'0') !='1' left join jsh_supplier s on jdh.organ_id=s.id and COALESCE(s.delete_flag,'0') !='1' left join jsh_user u on jdh.creator=u.id left join jsh_account a on jdh.account_id=a.id and COALESCE(a.delete_flag,'0') !='1' order by jdh.id desc

select dh.number,me.bar_code barCode, m."name" mname,m.model,m.standard,m.color,m.brand,m.mfrs,di.unit_price unitPrice,di.material_unit as mUnit, di.sku,
di.oper_number operNumber,di.all_price allPrice, COALESCE(di.tax_rate,0) taxRate, COALESCE(di.tax_money,0) taxMoney, COALESCE(di.tax_last_money,0) taxLastMoney,
s.supplier sname,d.dname dname, TO_CHAR(dh.oper_time, 'YYYY-MM-DD') operTime, concat(dh.sub_type,dh."type") as newType,
concat_ws('  ',dh.remark,di.remark) as newRemark
from jsh_depot_head dh
left join jsh_depot_item di on di.header_id=dh.id and COALESCE(di.delete_flag,'0') !='1'
left join jsh_material m on m.id=di.material_id and COALESCE(m.delete_flag,'0') !='1'
left join jsh_material_extend me on me.id=di.material_extend_id and COALESCE(me.delete_Flag,'0') !='1'
left join jsh_supplier s on s.id=dh.organ_id and COALESCE(s.delete_Flag,'0') !='1'
left join (select id,"name" as dName,delete_Flag from jsh_depot ) d on d.id=di.depot_id and COALESCE(d.delete_Flag,'0') !='1'
where dh.oper_time >=#{beginTime}::timestamp and dh.oper_time <=#{endTime}::timestamp

    and dh.organ_id = #{oId}


    and di.depot_id in

        #{item}



    and dh."type"=#{type}


    and (dh.sub_type!='采购' and dh.sub_type!='采购退货' and dh.sub_type!='销售' and dh.sub_type!='销售退货')


    and dh.creator in (

        #{creator}::bigint

    )


    and (dh.organ_id in (

        #{organId}::bigint

    ) or dh.sub_type='采购退货' or dh.sub_type='零售' or dh.sub_type='其它')


    and m.category_id in

        #{item}



    and dh.status = '1'



    and dh.number like #{bindNumber}



    and (me.bar_code like #{bindKey} or m."name" like #{bindKey} or m.mnemonic like #{bindKey} or m.standard like #{bindKey} or m.model like #{bindKey}
    or m.color like #{bindKey} or m.mfrs like #{bindKey} or m.brand like #{bindKey} or m.other_field1 like #{bindKey}
    or m.other_field2 like #{bindKey} or m.other_field3 like #{bindKey})


    and dh.creator=#{creator}::bigint



    and (dh.remark like #{bindRemark} or di.remark like #{bindRemark})

and dh.sub_type!='调拨'
and COALESCE(dh.delete_flag,'0') !='1'

    order by oper_time desc,number desc



        order by ${column}

            ${order}




    LIMIT #{rows} OFFSET #{offset}

