    and (dh.remark like #{bindRemark} or di.remark like #{bindRemark})

and COALESCE(dh.delete_flag,'0') !='1'

select *, (preBackInMoney+preBackOutMoney) as preBackMoney, (backInMoney+backOutMoney) as backMoney from (select s.id, s.supplier, s.contacts, s.telephone, s.phone_num, s.email, -- 起始期初金额 (case when s."type"='供应商' then COALESCE(s.begin_need_pay,0) else COALESCE(s.begin_need_get,0) end) begin_need, -- 上期欠款金额 (select COALESCE(sum(dh.discount_last_money),0)+COALESCE(sum(dh.other_money),0)-COALESCE(sum(dh.deposit),0)-abs(COALESCE(sum(dh.change_amount),0)) from jsh_depot_head dh where dh.organ_id=s.id and dh."type"=#{type} and dh.sub_type=#{subType} and dh.oper_time <= #{beginTime}::timestamp and COALESCE(dh.delete_flag,'0') !='1') preDebtMoney, -- 上期退货的欠款金额 (select COALESCE(sum(dh.discount_last_money),0)+COALESCE(sum(dh.other_money),0)-COALESCE(sum(dh.deposit),0)-abs(COALESCE(sum(dh.change_amount),0)) from jsh_depot_head dh where dh.organ_id=s.id and dh."type"=#{typeBack} and dh.sub_type=#{subTypeBack} and dh.oper_time <= #{beginTime}::timestamp and COALESCE(dh.delete_flag,'0') !='1') preReturnDebtMoney, -- 上期收款 (select COALESCE(sum(ai.each_amount),0) from jsh_account_item ai left join jsh_account_head ah on ai.header_id=ah.id and COALESCE(ah.delete_flag,'0') !='1' where ah.organ_id=s.id and ah."type"='收款' and ah.bill_time <= #{beginTime}::timestamp and COALESCE(ai.delete_flag,'0') !='1') preBackInMoney, -- 上期付款 (select 0-COALESCE(sum(ai.each_amount),0) from jsh_account_item ai left join jsh_account_head ah on ai.header_id=ah.id and COALESCE(ah.delete_flag,'0') !='1' where ah.organ_id=s.id and ah."type"='付款' and ah.bill_time <= #{beginTime}::timestamp and COALESCE(ai.delete_flag,'0') !='1') preBackOutMoney, -- 本期欠款 (select COALESCE(sum(dh.discount_last_money),0)+COALESCE(sum(dh.other_money),0)-COALESCE(sum(dh.deposit),0)-abs(COALESCE(sum(dh.change_amount),0)) from jsh_depot_head dh where dh.organ_id=s.id and dh."type"=#{type} and dh.sub_type=#{subType} and dh.oper_time>#{beginTime}::timestamp and dh.oper_time <= #{endTime}::timestamp and COALESCE(dh.delete_flag,'0') !='1') debtMoney, -- 本期退货的欠款金额 (select COALESCE(sum(dh.discount_last_money),0)+COALESCE(sum(dh.other_money),0)-COALESCE(sum(dh.deposit),0)-abs(COALESCE(sum(dh.change_amount),0)) from jsh_depot_head dh where dh.organ_id=s.id and dh."type"=#{typeBack} and dh.sub_type=#{subTypeBack} and dh.oper_time>#{beginTime}::timestamp and dh.oper_time <= #{endTime}::timestamp and COALESCE(dh.delete_flag,'0') !='1') returnDebtMoney, -- 本期收款 (select COALESCE(sum(ai.each_amount),0) from jsh_account_item ai left join jsh_account_head ah on ai.header_id=ah.id and COALESCE(ah.delete_flag,'0') !='1' where ah.organ_id=s.id and ah."type"='收款' and ah.bill_time>#{beginTime}::timestamp and ah.bill_time <= #{endTime}::timestamp and COALESCE(ai.delete_flag,'0') !='1') backInMoney, -- 本期付款 (select 0-COALESCE(sum(ai.each_amount),0) from jsh_account_item ai left join jsh_account_head ah on ai.header_id=ah.id and COALESCE(ah.delete_flag,'0') !='1' where ah.organ_id=s.id and ah."type"='付款' and ah.bill_time>#{beginTime}::timestamp and ah.bill_time <= #{endTime}::timestamp and COALESCE(ai.delete_flag,'0') !='1') backOutMoney from jsh_supplier s where s.enabled=true and s."type"=#{supplierType}
and s.id = #{organId}::bigint
and s.id in (
#{organId}::bigint
)
and COALESCE(s.delete_flag,'0') !='1') tb
where begin_need+preDebtMoney-preReturnDebtMoney-preBackInMoney-preBackOutMoney+debtMoney-returnDebtMoney-backInMoney-backOutMoney!=0
where begin_need+preDebtMoney-preReturnDebtMoney-preBackInMoney-preBackOutMoney+debtMoney-returnDebtMoney-backInMoney-backOutMoney=0
order by begin_need+preDebtMoney-preReturnDebtMoney-preBackInMoney-preBackOutMoney+debtMoney-returnDebtMoney-backInMoney-backOutMoney desc
LIMIT #{rows} OFFSET #{offset}

select dh.*, concat(dh.sub_type,dh."type") as depotHeadType, a."name" AccountName, s.supplier OrganName, s.contacts, s.telephone, s.address, s.bank_name, s.account_number, s.tax_num, s.phone_num from jsh_depot_head dh left join jsh_supplier s on dh.organ_id=s.id and COALESCE(s.delete_Flag,'0') !='1' left join jsh_account a on dh.account_id=a.id and COALESCE(a.delete_Flag,'0') !='1' where 1=1
and dh.number=#{number}
and COALESCE(dh.delete_flag,'0') !='1'

