from jsh_depot_head where 1=1 and organ_id in (
#{organId}::bigint
) and COALESCE(delete_flag,'0') !='1'

select
from jsh_depot_head where 1=1 and creator in (
#{creator}::bigint
) and COALESCE(delete_flag,'0') !='1'

select distinct dh.*, s.supplier OrganName, u.username userName from jsh_depot_head dh left join jsh_supplier s on dh.organ_id=s.id and COALESCE(s.delete_Flag,'0') !='1' left join jsh_user u on dh.creator=u.id and COALESCE(u.delete_flag,'0') !='1' left join jsh_depot_item di on dh.id = di.header_id and COALESCE(di.delete_flag,'0') !='1' left join jsh_material m on di.material_id = m.id and COALESCE(m.delete_flag,'0') !='1' where 1=1 and (dh."type"='入库' or dh."type"='出库') and (dh.sub_type='采购' or dh.sub_type='销售' or dh.sub_type='采购退货' or dh.sub_type='销售退货')
and dh.organ_id = #{organId}::bigint
and dh.status =#{status}
and dh.number like #{bindNumber}
and dh.oper_time >= #{beginTime}::timestamp
and dh.oper_time <= #{endTime}::timestamp
and (m."name" like #{bindKey} or m.standard like #{bindKey} or m.model like #{bindKey})
and di.depot_id in (
#{depotId}::bigint
)
and dh.creator in (
#{creator}::bigint
)
and (COALESCE(abs(dh.change_amount),0)+(select COALESCE(sum(abs(ai.each_amount)),0) from jsh_account_item ai where ai.bill_id=dh.id and COALESCE(ai.delete_flag,'0') !='1')) < (COALESCE(dh.discount_last_money,0) + COALESCE(dh.other_money,0) - COALESCE(dh.deposit,0)) and COALESCE(dh.delete_flag,'0') !='1' order by dh.oper_time desc
LIMIT #{rows} OFFSET #{offset}

select COALESCE(sum(dh.deposit),0)
from jsh_depot_head dh
where dh.link_number=#{linkNumber}
and dh.number!=#{number}
and COALESCE(dh.delete_flag,'0') !='1'

