select jdh.*, s.supplier OrganName, u.username userName, a."name" AccountName
from (select dh.id
from jsh_depot_head dh
left join jsh_depot_item di on dh.id = di.header_id and COALESCE(di.delete_flag,'0') !='1'
left join jsh_material m on di.material_id = m.id and COALESCE(m.delete_flag,'0') !='1'
left join jsh_material_extend me on di.material_extend_id = me.id and COALESCE(me.delete_flag,'0') !='1'
where 1=1

    and dh."type"=#{type}


    and dh.sub_type in (

        #{subType}

    )


    and dh.status in (

        #{status}

    )



    and dh.number like #{bindNumber}


    and dh.oper_time >= #{beginTime}::timestamp


    and dh.oper_time <= #{endTime}::timestamp



    and (me.bar_code like #{bindKey} or m."name" like #{bindKey} or m.standard like #{bindKey} or m.model like
    #{bindKey}
    or m.color like #{bindKey} or m.mfrs like #{bindKey} or m.other_field1 like #{bindKey}
    or m.other_field2 like #{bindKey} or m.other_field3 like #{bindKey})


    and di.depot_id in (

        #{depotId}::bigint

    )


    and dh.creator in (

        #{creator}::bigint

    )

and COALESCE(dh.delete_flag,'0') !='1'
group by dh.id
order by dh.id desc

    LIMIT #{rows} OFFSET #{offset}
) tb
left join jsh_depot_head jdh on jdh.id=tb.id and COALESCE(jdh.delete_flag,'0') !='1'
left join jsh_supplier s on jdh.organ_id=s.id and COALESCE(s.delete_flag,'0') !='1'
left join jsh_user u on jdh.creator=u.id and COALESCE(u.delete_flag,'0') !='1'
left join jsh_account a on jdh.account_id=a.id and COALESCE(a.delete_flag,'0') !='1'

